/* ═══════════════════════════════════════════════════════════════════
   avatar_render.js — shared VUmed avatar SVG renderer.
   SINGLE SOURCE for the avatar artwork: avatar_creator.html loads this
   file (its inline copies were removed 2026-07-12). Edit renderers HERE.
   Loaded as avatar_render.js?v=N — bump N in avatar_creator.html AND
   profile.html on every edit.
   Exposes classic globals (h2r, darken, lighten, DEFAULTS, renderBody,
   renderHead, renderHair, HAIR_STYLE_LABELS, OUTFIT_LABELS, buildSVG) + window.VumedAvatar.
═══════════════════════════════════════════════════════════════════ */
function h2r(hex) {
  const h = hex.replace('#','');
  return { r:parseInt(h.slice(0,2),16), g:parseInt(h.slice(2,4),16), b:parseInt(h.slice(4,6),16) };
}
function r2h({r,g,b}) {
  return '#'+[r,g,b].map(v=>Math.min(255,Math.max(0,Math.round(v))).toString(16).padStart(2,'0')).join('');
}
function darken(hex,a)  { const c=h2r(hex); return r2h({r:c.r*(1-a),g:c.g*(1-a),b:c.b*(1-a)}); }
function lighten(hex,a) { const c=h2r(hex); return r2h({r:c.r+(255-c.r)*a,g:c.g+(255-c.g)*a,b:c.b+(255-c.b)*a}); }

