/* ══════════════════════════════════════════════════════════
   STETHOSCOOP — equippable accessory (Accessoires tab).
   The stethoscope artwork is BAKED INTO each outfit's paths, so
   unequipping = stripping those paths from the outfit's markup by
   fill colour. Verified per outfit (red-highlight scan 2026-07-14)
   that these fills are used by the stethoscope ONLY:
   - Dokter: the 12 dark/grey paths listed in STETHO_FILLS_DOCTOR
     (neck tube, earpiece loop, chest piece).
   - Chirurg: the two #d8d8d8 hanging-tube paths.
   Unequip = RECOLOR those paths to coat-white (#fefefe), NOT strip:
   in the Dokter artwork the stethoscope sits in stethoscope-shaped
   HOLES of the coat's border-trace path, so stripping shows the
   page background through the holes — the recolored paths cover
   their own holes exactly (verified: the red-highlight scan showed
   no grey slivers). Keeps paint order intact in both states.
   CHIRURG (2026-07-14, "wear the stethoscope with the surgeon
   outfit"): equipping paints the DOKTER's stethoscope as an
   overlay on top of the surgeon body — stethoOverlay() extracts
   the doctor's 12 static stethoscope paths at runtime (cached,
   stays in sync with the doctor artwork) and rewraps them in the
   doctor's own transform; both bodies anchor the neck at (200,248)
   so it lands correctly. The surgeon artwork's OWN thin hanging
   tubes (#d8d8d8) are whiteouted in BOTH states — with the real
   stethoscope they read as a duplicate. New outfits: bake a
   stethoscope in + list its fills, or just rely on stethoOverlay().
═══════════════════════════════════════════════════════════ */
const STETHO_LABELS = ['Geen','Stethoscoop','Goud'];
const STETHO_FILLS_DOCTOR  = ['#242424','#232323','#0f0f0f','#b3b3b3','#b6b6b6','#b1b1b1','#666','#bababa','#bcbcbc'];
const STETHO_FILLS_SURGEON = ['#d8d8d8'];
function hasStetho(s) { return (s.stethoscope === undefined ? 1 : s.stethoscope) >= 1; }
function isGoldStetho(s) { return s.stethoscope === 2; }
/* GOLD SKIN (shop item stetho_gold, stethoscope=2): only the GREY metal
   fills go gold — the dark rubber-tube fills (#242424/#232323/#0f0f0f)
   stay black. Each grey maps to a gold of matching lightness. */
const STETHO_GOLD_MAP = {
  '#bcbcbc':'#FFD64F', '#bababa':'#FFD246', '#b6b6b6':'#FCCB35',
  '#b3b3b3':'#F9C526', '#b1b1b1':'#F5BF1C', '#666':'#B08508',
};
function goldFills(svg) {
  return svg.replace(/<path fill="([^"]+)"/g, function (m, f) {
    return STETHO_GOLD_MAP[f] ? '<path fill="' + STETHO_GOLD_MAP[f] + '"' : m;
  });
}
function whiteoutFills(svg, fills) {
  return svg.replace(/<path fill="([^"]+)"/g, function (m, f) {
    return fills.indexOf(f) !== -1 ? '<path fill="#fefefe"' : m;
  });
}
let _stethoOverlayCache = null;
function stethoOverlay() {
  if (_stethoOverlayCache === null) {
    // skin/cloth args are irrelevant: the stethoscope paths are static
    const doc = renderBodyDoctor({stethoscope:1}, '#000', '#000');
    const all = doc.match(/<path fill="[^"]+"[^>]*\/>/g) || [];
    const own = all.filter(function (p) {
      return STETHO_FILLS_DOCTOR.some(function (f) { return p.indexOf('fill="' + f + '"') !== -1; });
    });
    _stethoOverlayCache = '<g transform="translate(-58.8,-66.03) scale(0.5815)">' + own.join('') + '</g>';
  }
  return _stethoOverlayCache;
}

