var BODY_STANDARD = "<g><path fill=\"#6d9dc4\" d=\"M605.01,0l.53,34c53.15-11.84,98.29,20.28,114.41,69.45l178.51,544.73-10.26,1.14-174.45,51.42-28.79-88.88-2.6-6.43.05-143.39H237.66s.01,107.06.01,107.06l-3.01,6.33-43.22,134.64-6.22-3.37-175.42-60.3L185.94,98.59c15.81-49.16,66.71-76.98,117.09-63.6l-.35-34.98h302.31Z\"/><polygon fill=\"#d1d7dc\" points=\"237.67 575.51 234.66 575.44 237.67 569.12 237.67 575.51\"/></g><path fill=\"#d3b3a6\" d=\"M346.87.23c20.02,39.75,61.17,67.04,108.72,67.04h0c47.55,0,88.7-27.29,108.72-67.04h-217.43Z\"/><g><g><path fill=\"#eec9bc\" d=\"M898.45,645.73l5.48,24.81c4.8,29.36-3.15,58.77-19.99,81.96l-145.34-.16c-13.93-16.07-18.98-34.26-24.86-52.83l174.45-52.62,10.26-1.17Z\"/><path fill=\"#eec9bc\" d=\"M191.44,709.06c-4.72,15.05-11.09,29.78-20.43,42.67l-151.02.75c-23.04-31.68-25.78-73.04-10.18-108.58l175.42,61.7,6.22,3.45Z\"/></g><rect fill=\"#4c7ba8\" x=\"237.67\" y=\"455.77\" width=\"447.43\" height=\"296.72\"/><path fill=\"#426b91\" d=\"M467,752.56h-25.59s-.01-66.28-.01-66.28l-7.98-.3c-6.37-.24-10.58-4.18-10.61-10.28-.03-5.77,4.35-10.18,10.59-10.14l44.2.23c4.24.02,7.89,6.28,7.87,9.93-.02,3.94-3.74,9.62-7.62,9.86l-10.85.67v66.32Z\"/></g>";
