const HAIR_STYLE_LABELS = HAIR_STYLES.map(function(h){ return h.label; });
function hairIsBack(s) {
  if (s.hairItem) return false;   // dynamic hair paints in the front layer
  const st = HAIR_STYLES[s.hairStyle || 0];
  return !!(st && st.back);
}
function renderHair(s) {
  if (s.hairItem) return renderDynItem(s.hairItem, s.hairColor, s.clothingColor);
  const idx = s.hairStyle || 0;
  const st = HAIR_STYLES[idx] || HAIR_STYLES[0];
  // Authoring hook (avatar_creator "verplaats & schaal" tool): window.HAIR_TF_EDITS
  // maps a style index to an override transform string. Undefined everywhere except
  // the creator while editing, so all other pages render the baked st.tf unchanged.
  let tf = st.tf;
  if (typeof window !== 'undefined' && window.HAIR_TF_EDITS && window.HAIR_TF_EDITS[idx] != null)
    tf = window.HAIR_TF_EDITS[idx];
  return `<g data-hair="1" transform="${tf}"><path fill="${s.hairColor}" d="${st.d}"/></g>`;
}
/* underD: optional filler shape (avatar coords, no transform) painted BEHIND
   the head in hair colour. Used by "Lang": its two falls have straight inner
   edges (avatar x72 / x333) but the head narrows at the jaw (edge recedes to
   x93..306 by y240) and the cheek is a hair-width shy on the right (head 329 <
   hair 333), leaving thin background slivers between head and hair. A rectangle
   behind the head plugs exactly those gaps — it only reveals hair colour where
   the head is absent, and its edges tuck under the front falls / head, so no
   seam. Bounded to the jaw band (y148..249) so it never shows below the chin. */
function renderHairUnder(s) {
  if (s.hairItem) return '';
  const st = HAIR_STYLES[s.hairStyle || 0] || HAIR_STYLES[0];
  if (!st.underD) return '';
  return `<path fill="${s.hairColor}" d="${st.underD}"/>`;
}

/* ══════════════════════════════════════════════════════════
   ACCESSOIRES — "Overig" slot. Style 1 = surgical headlamp
   (designed in-code, not artwork): dark strap around the skull
   (drawn OVER the hair, like it's strapped on) + round metal
   lamp with a warm lens on the forehead. Fixed equipment colors,
   not themable. Head geometry: skull x57-342 (top y20), eyes
   from y~62, face center x~197.
══════════════════════════════════════════════════════════ */
const ACC_OVERIG_LABELS = ['Geen','Voorhoofdslamp','Goud'];
/* Surgical head light ("voorhoofdslamp"): a band that arcs across the
   forehead and curves down to the temples (drawn OVER the hair, like it's
   strapped on) with a round lamp + warm lens mounted at the centre.
   GOLD SKIN (shop item headlamp_gold, accOverig=2): the metal band +
   bezel + reflector go gold; the warm lens/highlight stay unchanged.
   Head geometry: skull x57-342 (top y20), ears x35/x364 @y95, eyes y~62. */
function renderAccOverig(s) {
  const v = s.accOverig || 0;
  if (v !== 1 && v !== 2) return '';
  const gold = v === 2;
  const strap  = gold ? '#C99A12' : '#3E5060';
  const strapL = gold ? '#E9C24A' : '#5A6E7E';
  const bezel  = gold ? '#F5BF1C' : '#8FA6B2';
  const dish   = gold ? '#FFF0C2' : '#DDE7EC';
  // Straight band across the forehead from temple to temple.
  const band = 'M50,40 H344';
  const inner = `
    <path d="${band}" fill="none" stroke="${strap}" stroke-width="26" stroke-linecap="round"/>
    <path d="${band}" fill="none" stroke="${strapL}" stroke-width="7" stroke-linecap="round" opacity="0.6"/>
    <circle cx="197" cy="40" r="26" fill="${bezel}"/>
    <circle cx="197" cy="40" r="20" fill="${dish}"/>
    <circle cx="197" cy="40" r="12.5" fill="#FFE08A"/>
    <ellipse cx="192" cy="35" rx="4.5" ry="3.5" fill="#FFF6D8"/>`;
  // Authoring hook (avatar_creator "verplaats & schaal" tool): window.ACC_TF_EDITS
  // holds an override transform (keyed by index 0 — the shared headlamp shape).
  // Only set while editing in the creator, so other pages render the baked
  // placement unchanged. Bake the exported tf here to make it permanent.
  let tf = '';
  if (typeof window !== 'undefined' && window.ACC_TF_EDITS && window.ACC_TF_EDITS[0] != null)
    tf = window.ACC_TF_EDITS[0];
  return `<g${tf ? ` transform="${tf}"` : ''}>${inner}</g>`;
}

/* ══════════════════════════════════════════════════════════
   MASTER SVG BUILDER
   mode: 'full' | 'head'
   'full'  → viewBox -30 -90 460 650 (complete character)
   'head'  → viewBox -33 -98 472 472 (square portrait crop for circle
             avatars: full head + hair + upper body)
══════════════════════════════════════════════════════════ */
function buildSVG(s, mode='full') {
  const skin  = s.skin;
  const cloth = s.clothingColor;
  let out = '';

  // NO background rect in any mode: the page showing the avatar paints
  // s.bgColor itself (creator preview-pane / circle containers). A rect here
  // made a narrow strip that clipped long hair and double-painted the bg.
  // Dynamic background item (if equipped) paints behind everything else.
  if (s.bgItem) out += renderDynItem(s.bgItem, s.hairColor, cloth);
  // Body renders in BOTH modes — the head crop shows part of the upper body.
  out += renderBody(s, skin, cloth);
  // (neck/chest skin is part of the standard body artwork)

  // A dynamic Hoofddeksel (headwear) HIDES the hair entirely — a headscarf/cap
  // covers the whole scalp, so no hair (front, back, or under-filler) is drawn.
  const hideHair = !!s.headwearItem;
  // A headwear item flagged hideEars (a hoofddoek/hijab wrapping the face) also
  // clips the baked-in ears away so they don't poke out past the scarf.
  const hideEars = !!(s.headwearItem && s.headwearItem.hideEars);

  // Back-layer hair paints BEHIND the head (mass around the skull)
  if (!hideHair && hairIsBack(s)) out += renderHair(s);
  // Optional squeezed under-copy behind the head (fills chin-corner notches)
  if (!hideHair && !hairIsBack(s)) out += renderHairUnder(s);

  // Standard head (skull + ears + face baked into the artwork) — ears clipped
  // off when a face-covering headwear is worn.
  out += hideEars ? clipEars(renderHead(s, skin)) : renderHead(s, skin);

  // Standard hair (always on, recolored by Haarkleur) — suppressed under headwear
  if (!hideHair && !hairIsBack(s)) out += renderHair(s);

  // Bril (glasses) — dynamic slot, sits on the face above the hair.
  if (s.glassesItem) out += renderDynItem(s.glassesItem, s.hairColor, cloth);
  // Hoofddeksel (headwear) — dynamic slot, sits over the head/hair. recolor
  // 'accent' follows Hoofddoekkleur (s.headwearColor).
  if (s.headwearItem) out += renderDynItem(s.headwearItem, s.hairColor, cloth, s.headwearColor);

  // Accessoires — "Overig" slot (headlamp straps over the hair)
  out += renderAccOverig(s);

  // Dynamic accessory item (if equipped) paints on the very top layer.
  if (s.accItem) out += renderDynItem(s.accItem, s.hairColor, cloth);
  // Overig (misc, e.g. mondkapje) paints on the very top. recolor 'accent'
  // follows Mondkapjekleur (s.miscColor).
  if (s.miscItem) out += renderDynItem(s.miscItem, s.hairColor, cloth, s.miscColor);

  // Full viewBox is wider than the 400-wide body canvas: the "Lang" hair
  // artwork spans x -21 .. 428, so x -30..430 keeps it unclipped.
  // 'head' = SQUARE portrait crop for circle avatars: the smallest circle
  // containing head + long hair is center (203.4, 138) r~228 (pixel-scanned),
  // padded to r=236. Shifted up 18 units (y -98 → -116, same 472 size so the
  // face stays the same size) so tall hair — the Knot bun tops out at avatar
  // y≈-89 — clears the inscribed display circle instead of being flattened
  // against its top edge. viewBox -33 -116 472 472. Shows full head/hair +
  // upper body, nothing touches a circular mask.
  const vb = mode === 'head' ? '-33 -116 472 472' : '-30 -90 460 650';
  return `<svg viewBox="${vb}" xmlns="http://www.w3.org/2000/svg">${out}</svg>`;
}

/* Convenience API for pages that only consume the avatar */
window.VumedAvatar = {
  DEFAULTS: DEFAULTS,
  build: buildSVG,
  hasCustom: function () { try { return !!localStorage.getItem('vumed_avatar'); } catch (e) { return false; } },
  getState: function () {
    try { return Object.assign({}, DEFAULTS, JSON.parse(localStorage.getItem('vumed_avatar') || '{}')); }
    catch (e) { return Object.assign({}, DEFAULTS); }
  }
};
